#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->pump_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_level = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .pump_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_pump_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_pump_on = controller->pump_on;
    previous_state = controller->state;

    /* Control policy: */
    /* - default to PUMP OFF on boot */
    /* - turn the pump on when LEVEL < 30 */
    /* - turn the pump off when LEVEL > 80 */
    /* - hold the previous safe output while 30 <= LEVEL <= 80 */
    /* - fail safe to PUMP OFF on malformed input or timeout */

    if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_sensor = true;
        controller->last_level = input.level;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Fail safe: if no valid sensor, pump off */
        if (!controller->has_valid_sensor) {
            controller_set_safe_off(controller);
            output.pump_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
            output.changed = true;
            return output;
        }

        /* Check thresholds */
        if (input.level < CONTROLLER_LEVEL_LOW_THRESHOLD) {
            /* Pump on when low level */
            controller->pump_on = true;
            controller->state = CONTROLLER_STATE_PUMPING;
            output.pump_on = true;
            output.state = CONTROLLER_STATE_PUMPING;
            output.state_name = controller_state_name(CONTROLLER_STATE_PUMPING);
            output.changed = true;
        } else if (input.level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
            /* Pump off when high level */
            controller->pump_on = false;
            controller->state = CONTROLLER_STATE_SAFE_OFF;
            output.pump_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
            output.changed = true;
        } else {
            /* Mid-band level: hold previous safe output */
            if (controller->pump_on) {
                /* Still pumping, but now in band - stay holding */
                output.pump_on = controller->pump_on;
                output.state = CONTROLLER_STATE_HOLDING;
                output.state_name = controller_state_name(CONTROLLER_STATE_HOLDING);
                output.changed = true;
            } else {
                /* Not pumping, but in band - stay off */
                output.pump_on = false;
                output.state = CONTROLLER_STATE_SAFE_OFF;
                output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
                output.changed = true;
            }
        }
    } else if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        /* Fail safe on timeout */
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        output.pump_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = true;
    } else if (input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        /* Fail safe on invalid level */
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        output.pump_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = true;
    }

    output.changed = (previous_pump_on != controller->pump_on) || 
                     (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PUMPING:
        return "STATE PUMPING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
        return "STATE SAFE_OFF";
    default:
        return "STATE UNKNOWN";
    }
}

